document.addEventListener("DOMContentLoaded",function(){const filtrosPeriodo=document.querySelectorAll(".filtro-opcao.filtro-periodo");filtrosPeriodo.forEach(filtro=>{filtro.addEventListener("click",function(){const periodo=this.getAttribute("data-periodo");document.querySelectorAll(".filtro-opcao.filtro-periodo").forEach(f=>{f.classList.remove("ativo")});this.classList.add("ativo");document.querySelectorAll(".periodo-card").forEach(card=>{card.style.display="none"});document.querySelectorAll(`.periodo-card[data-periodo="${periodo}"]`).forEach(card=>{card.style.display="block";card.classList.add("ativo")});atualizarBotoesContratacao()})});function atualizarBotoesContratacao(){["essencial","premium"].forEach(planoTipo=>{const cardAtivo=document.querySelector(`.bio-plano.${planoTipo} .periodo-card.ativo`);if(!cardAtivo)return;const periodo=cardAtivo.getAttribute("data-periodo");document.querySelectorAll(`.${planoTipo}-link-mensal, .${planoTipo}-link-trimestral, .${planoTipo}-link-semestral`).forEach(botao=>{botao.style.display="none"});const botaoAtivo=document.querySelector(`.${planoTipo}-link-${periodo}`);if(botaoAtivo){botaoAtivo.style.display="inline-block"}})}const periodoAtivo=document.querySelector(".filtro-opcao.filtro-periodo.ativo").getAttribute("data-periodo");document.querySelectorAll(".periodo-card").forEach(card=>{card.style.display="none"});document.querySelectorAll(`.periodo-card[data-periodo="${periodoAtivo}"]`).forEach(card=>{card.style.display="block";card.classList.add("ativo")});atualizarBotoesContratacao()});